begin;

insert into public.questions (
  id, section, context, difficulty, tags, question, options, answer,
  explanation_en, explanation_ne, source_type, reference_scope, official_notice, status, is_active
) values
('lt-a-vocab-001', 'Vocabulary', 'daily_life', 'easy', array['noun', 'daily-life']::text[], '다음 중 ''water''의 뜻은 무엇입니까?', '["밥","물","집","책"]'::jsonb, '물', '''물'' means water in Korean.', '''물'' को अर्थ कोरियन भाषामा पानी हो।', 'original', 'Original practice item aligned with general EPS-TOPIK everyday-life and workplace vocabulary preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-vocab-002', 'Vocabulary', 'workplace', 'easy', array['verb', 'work']::text[], '빈칸에 알맞은 말을 고르십시오. 저는 공장에서 ______.', '["일합니다","잡니다","삽니다","먹습니다"]'::jsonb, '일합니다', '''일합니다'' means ''work'' and fits the factory sentence.', '''일합니다'' को अर्थ काम गर्छु/गर्छ भन्ने हुन्छ, त्यसैले कारखानाको वाक्यमा मिल्छ।', 'original', 'Original practice item aligned with general EPS-TOPIK everyday-life and workplace vocabulary preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-vocab-003', 'Vocabulary', 'safety', 'medium', array['safety', 'workplace']::text[], '''안전모''와 관계있는 것은 무엇입니까?', '["머리 보호","점심 식사","출근 시간","한국어 책"]'::jsonb, '머리 보호', '''안전모'' is a safety helmet used to protect the head.', '''안전모'' टाउको जोगाउने सुरक्षा हेल्मेट हो।', 'original', 'Original practice item aligned with general EPS-TOPIK everyday-life and workplace vocabulary preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-vocab-004', 'Vocabulary', 'daily_life', 'medium', array['adjective', 'opposites']::text[], '반대말을 고르십시오. ''빠르다''', '["작다","느리다","멀다","춥다"]'::jsonb, '느리다', 'The opposite of ''빠르다'' (fast) is ''느리다'' (slow).', '''빠르다'' को उल्टो अर्थ ''느리다'' अर्थात् ढिलो हो।', 'original', 'Original practice item aligned with general EPS-TOPIK everyday-life and workplace vocabulary preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-vocab-005', 'Vocabulary', 'manufacturing', 'medium', array['verb', 'maintenance']::text[], '다음 중 ''to repair''의 뜻에 가장 가까운 말은 무엇입니까?', '["고치다","버리다","기다리다","빌리다"]'::jsonb, '고치다', '''고치다'' means to fix or repair something.', '''고치다'' को अर्थ बिग्रिएको कुरा मिलाउनु वा मर्मत गर्नु हो।', 'original', 'Original practice item aligned with general EPS-TOPIK everyday-life and workplace vocabulary preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-grammar-001', 'Grammar', 'daily_life', 'easy', array['particle', 'origin']::text[], '빈칸에 알맞은 조사를 고르십시오. 저는 네팔______ 왔습니다.', '["이","을","에서","도"]'::jsonb, '에서', '''에서'' is used with a place of origin in this sentence.', 'यो वाक्यमा आएको ठाउँ नेपल हो, त्यसैले उद्गम स्थान देखाउन ''에서'' प्रयोग हुन्छ।', 'original', 'Original practice item aligned with common EPS-TOPIK grammar preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-grammar-002', 'Grammar', 'daily_life', 'easy', array['particle', 'object']::text[], '알맞은 문장을 고르십시오.', '["저는 한국어를 공부합니다.","저는 한국어가 공부합니다.","저는 한국어에 공부합니다.","저는 한국어도 공부합니다에."]'::jsonb, '저는 한국어를 공부합니다.', '''한국어를 공부합니다'' correctly marks Korean as the object of study.', '''한국어를 공부합니다'' मा ''를'' ले 한국어 लाई पढ्ने वस्तुका रूपमा जनाउँछ।', 'original', 'Original practice item aligned with common EPS-TOPIK grammar preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-grammar-003', 'Grammar', 'daily_life', 'medium', array['future', 'condition']::text[], '빈칸에 알맞은 말을 고르십시오. 내일 비가 오면 집에 ______.', '["있겠습니다","있었습니다","있고","있는"]'::jsonb, '있겠습니다', 'The sentence talks about tomorrow, so the future form ''있겠습니다'' fits.', 'वाक्यले भोलिको कुरा गर्छ, त्यसैले भविष्य जनाउने ''있겠습니다'' मिल्छ।', 'original', 'Original practice item aligned with common EPS-TOPIK grammar preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-grammar-004', 'Grammar', 'daily_life', 'medium', array['connector', 'reason']::text[], '두 문장을 자연스럽게 연결한 것을 고르십시오. 일이 많습니다. 그래서 피곤합니다.', '["일이 많아서 피곤합니다.","일이 많지만 피곤합니다.","일이 많으러 피곤합니다.","일이 많거나 피곤합니다."]'::jsonb, '일이 많아서 피곤합니다.', '''-아서/어서'' shows reason, so ''일이 많아서'' means ''because there is much work.''', '''-아서/어서'' ले कारण जनाउँछ, त्यसैले ''일이 많아서'' को अर्थ काम धेरै भएकाले हो।', 'original', 'Original practice item aligned with common EPS-TOPIK grammar preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-grammar-005', 'Grammar', 'workplace', 'hard', array['obligation', 'workplace']::text[], '빈칸에 알맞은 말을 고르십시오. 작업 전에 기계를 ______ 합니다.', '["확인해야","확인해서","확인하면","확인한"]'::jsonb, '확인해야', '''-아/어야 합니다'' means ''must,'' so workers must check the machine before work.', '''-아/어야 합니다'' ले गर्नै पर्छ भन्ने अर्थ दिन्छ, त्यसैले काम अघि मेसिन जाँच गर्नुपर्छ।', 'original', 'Original practice item aligned with common EPS-TOPIK grammar preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-reading-001', 'Reading', 'daily_life', 'easy', array['time', 'reading']::text[], '민수 씨는 아침 8시에 회사에 갑니다. 12시에 점심을 먹습니다. 민수 씨는 몇 시에 점심을 먹습니까?', '["8시","10시","12시","6시"]'::jsonb, '12시', 'The text says he eats lunch at 12 o''clock.', 'पाठमा उसले १२ बजे खाना खान्छ भनिएको छ।', 'original', 'Original practice item aligned with general EPS-TOPIK short reading and notice comprehension preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-reading-002', 'Reading', 'daily_life', 'easy', array['day', 'reading']::text[], '오늘은 일요일입니다. 수지 씨는 회사에 가지 않습니다. 무엇이 맞습니까?', '["수지 씨는 오늘 일합니다.","수지 씨는 오늘 쉽니다.","수지 씨는 오늘 학교에 갑니다.","수지 씨는 오늘 병원에 갑니다."]'::jsonb, '수지 씨는 오늘 쉽니다.', 'She does not go to work on Sunday, so she rests today.', 'आइतबार काममा जाँदैन भनिएकाले सुजी आज आराम गर्छिन्।', 'original', 'Original practice item aligned with general EPS-TOPIK short reading and notice comprehension preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-reading-003', 'Reading', 'administrative', 'medium', array['notice', 'rules']::text[], '안내문: 휴게실에서는 음식을 먹을 수 있습니다. 하지만 담배를 피우면 안 됩니다. 휴게실에서 할 수 없는 것은 무엇입니까?', '["쉬기","음식 먹기","담배 피우기","물 마시기"]'::jsonb, '담배 피우기', 'The notice says smoking is not allowed in the break room.', 'सूचनामा विश्राम कक्षमा धूम्रपान गर्न पाइँदैन भनिएको छ।', 'original', 'Original practice item aligned with general EPS-TOPIK short reading and notice comprehension preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-reading-004', 'Reading', 'daily_life', 'medium', array['health', 'reason']::text[], '지훈 씨는 감기에 걸렸습니다. 그래서 오늘 병원에 가고 약을 샀습니다. 지훈 씨는 왜 병원에 갔습니까?', '["일이 많아서","감기에 걸려서","친구를 만나서","약속이 있어서"]'::jsonb, '감기에 걸려서', 'He went to the hospital because he had a cold.', 'जिहुनलाई रुघा लागेको थियो, त्यसैले ऊ अस्पताल गएको हो।', 'original', 'Original practice item aligned with general EPS-TOPIK short reading and notice comprehension preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-reading-005', 'Reading', 'administrative', 'medium', array['notice', 'work-schedule']::text[], '공지: 다음 주 월요일부터 작업 시간이 오전 9시에서 오전 8시 30분으로 바뀝니다. 직원들은 몇 시까지 와야 합니까?', '["8시","8시 30분","9시","9시 30분"]'::jsonb, '8시 30분', 'The new start time is 8:30 a.m., so workers should arrive by then.', 'नयाँ सुरु हुने समय बिहान ८:३० हो, त्यसैले कर्मचारीहरू त्यतिबेलासम्म आउनुपर्छ।', 'original', 'Original practice item aligned with general EPS-TOPIK short reading and notice comprehension preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-workplace-001', 'Workplace Korean', 'workplace', 'easy', array['instruction', 'place']::text[], '상사가 ''회의실로 오세요''라고 말했습니다. 어디로 가야 합니까?', '["식당","회의실","기숙사","은행"]'::jsonb, '회의실', '''회의실'' means meeting room.', '''회의실'' को अर्थ बैठक कोठा हो।', 'original', 'Original practice item aligned with general workplace Korean safety and communication preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-workplace-002', 'Workplace Korean', 'safety', 'easy', array['safety', 'injury']::text[], '작업장에서 다쳤습니다. 먼저 무엇을 해야 합니까?', '["혼자 계속 일합니다.","관리자에게 말합니다.","집에 갑니다.","친구에게만 말합니다."]'::jsonb, '관리자에게 말합니다.', 'In a workplace injury, you should first tell a supervisor or manager.', 'काम गर्ने ठाउँमा चोट लागेपछि पहिले व्यवस्थापकलाई भन्नुपर्छ।', 'original', 'Original practice item aligned with general workplace Korean safety and communication preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-workplace-003', 'Workplace Korean', 'safety', 'medium', array['machine', 'safety']::text[], '기계가 이상한 소리를 냅니다. 알맞은 행동은 무엇입니까?', '["기계를 바로 멈추고 보고합니다.","더 빨리 일합니다.","소리를 무시합니다.","안전모를 벗습니다."]'::jsonb, '기계를 바로 멈추고 보고합니다.', 'If a machine sounds unusual, stop it safely and report the issue.', 'मेसिनले अनौठो आवाज निकाल्दा सुरक्षित रूपमा रोक्नुपर्छ र रिपोर्ट गर्नुपर्छ।', 'original', 'Original practice item aligned with general workplace Korean safety and communication preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-workplace-004', 'Workplace Korean', 'workplace', 'medium', array['instruction', 'storage']::text[], '동료가 ''이 박스를 창고에 놓아 주세요''라고 했습니다. 무엇을 해야 합니까?', '["박스를 버립니다.","박스를 창고에 둡니다.","박스를 집에 가져갑니다.","박스를 엽니다."]'::jsonb, '박스를 창고에 둡니다.', '''창고에 놓아 주세요'' means ''please put it in the storage room.''', '''창고에 놓아 주세요'' को अर्थ कृपया सामान गोदाममा राख्नुहोस् हो।', 'original', 'Original practice item aligned with general workplace Korean safety and communication preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true),
('lt-a-workplace-005', 'Workplace Korean', 'safety', 'hard', array['ppe', 'obligation']::text[], '작업 전에 보호 장갑을 착용해야 합니다. 이 문장의 뜻은 무엇입니까?', '["작업 후에 장갑을 삽니다.","작업 전에 장갑을 껴야 합니다.","장갑 없이 일해도 됩니다.","장갑은 휴게실에 있습니다."]'::jsonb, '작업 전에 장갑을 껴야 합니다.', '''착용해야 합니다'' means ''must wear,'' so gloves are required before work.', '''착용해야 합니다'' को अर्थ लगाउनै पर्छ हो, त्यसैले काम अघि पन्जा लगाउनुपर्छ।', 'original', 'Original practice item aligned with general workplace Korean safety and communication preparation scope.', 'This is an original practice question. It is not an official EPS-TOPIK question and is not copied from any official textbook or past exam.', 'published', true)
on conflict (id) do update set
  section = excluded.section,
  context = excluded.context,
  difficulty = excluded.difficulty,
  tags = excluded.tags,
  question = excluded.question,
  options = excluded.options,
  answer = excluded.answer,
  explanation_en = excluded.explanation_en,
  explanation_ne = excluded.explanation_ne,
  source_type = excluded.source_type,
  reference_scope = excluded.reference_scope,
  official_notice = excluded.official_notice,
  status = excluded.status,
  is_active = excluded.is_active;

